import hashlib
import unicodedata

def mystery(x):
    if not isinstance(x, str):
        return False
    try:
        y = unicodedata.normalize("NFKC", x)
    except Exception:
        return False
    if len(y) != 43 or len(x) != 43:
        return False
    if max(ord(ch) for ch in x) <= 0xFFFF:
        return False
    try:
        b = y.encode("ascii")
    except Exception:
        return False
    return hashlib.md5(b).hexdigest() == "9e107d9d372bb6826bd81d3542a419d6"
